import json
import hashlib
import logging
import os
import re
import time
from datetime import datetime, timezone
from typing import Any, Optional

from google.cloud import firestore, pubsub_v1, storage
from google.api_core import exceptions as gcp_exceptions

# Configure structured logging - ensure no sensitive data leaks
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Configuration from environment variables (not hardcoded)
ALLOWED_BUCKET = os.environ.get("ALLOWED_BUCKET", "")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "")
ALLOWED_EXTENSIONS = os.environ.get("ALLOWED_FILE_EXTENSIONS", ".csv,.json,.txt").split(",")
MAX_FILE_SIZE_MB = int(os.environ.get("MAX_FILE_SIZE_MB", "50"))
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")

# Compile validation patterns once
_SAFE_FILENAME_PATTERN = re.compile(r"^[a-zA-Z0-9][a-zA-Z0-9_\-./]{0,1023}$")
_PATH_TRAVERSAL_PATTERN = re.compile(r"\.\.")


class InputValidationError(Exception):
    """Raised when input validation fails."""
    pass


class SecurityViolationError(Exception):
    """Raised when a security constraint is violated."""
    pass


def _validate_bucket_name(bucket_name: str) -> str:
    """Validate and allowlist the bucket name."""
    if not bucket_name or not isinstance(bucket_name, str):
        raise InputValidationError("Bucket name is required and must be a string")

    bucket_name = bucket_name.strip()

    if not ALLOWED_BUCKET:
        raise SecurityViolationError("ALLOWED_BUCKET environment variable not configured")

    if bucket_name != ALLOWED_BUCKET:
        # Do NOT log the actual bucket name to avoid information leakage
        raise SecurityViolationError("Bucket not in allowlist")

    return bucket_name


def _validate_file_name(file_name: str) -> str:
    """Validate file name against injection and traversal attacks."""
    if not file_name or not isinstance(file_name, str):
        raise InputValidationError("File name is required and must be a string")

    file_name = file_name.strip()

    # Check for path traversal
    if _PATH_TRAVERSAL_PATTERN.search(file_name):
        raise SecurityViolationError("Path traversal detected in file name")

    # Check against safe filename pattern
    if not _SAFE_FILENAME_PATTERN.match(file_name):
        raise InputValidationError("File name contains invalid characters")

    # Check file extension allowlist
    file_lower = file_name.lower()
    if not any(file_lower.endswith(ext.lower().strip()) for ext in ALLOWED_EXTENSIONS):
        raise InputValidationError(
            f"File extension not allowed. Permitted: {ALLOWED_EXTENSIONS}"
        )

    # Prevent null bytes
    if "\x00" in file_name:
        raise SecurityViolationError("Null byte detected in file name")

    return file_name


def _validate_file_size(blob: storage.Blob) -> None:
    """Validate file size before processing."""
    blob.reload()
    size_mb = (blob.size or 0) / (1024 * 1024)
    if size_mb > MAX_FILE_SIZE_MB:
        raise InputValidationError(
            f"File size {size_mb:.1f}MB exceeds maximum {MAX_FILE_SIZE_MB}MB"
        )
    if blob.size == 0:
        raise InputValidationError("File is empty")


def _sanitize_for_logging(value: str, max_length: int = 100) -> str:
    """Sanitize a value for safe logging - remove sensitive patterns."""
    if not value:
        return "<empty>"
    # Truncate
    sanitized = value[:max_length]
    # Remove control characters
    sanitized = re.sub(r"[\x00-\x1f\x7f-\x9f]", "", sanitized)
    return sanitized


def _compute_file_hash(content: bytes) -> str:
    """Compute SHA-256 hash of file content for integrity verification."""
    return hashlib.sha256(content).hexdigest()


def _get_storage_client() -> storage.Client:
    """Get Storage client (uses ADC - Application Default Credentials)."""
    return storage.Client()


def _get_firestore_client() -> firestore.Client:
    """Get Firestore client (uses ADC)."""
    return firestore.Client()


def _get_pubsub_publisher() -> pubsub_v1.PublisherClient:
    """Get Pub/Sub publisher client (uses ADC)."""
    return pubsub_v1.PublisherClient()


def _read_file_from_storage(bucket_name: str, file_name: str) -> tuple[bytes, dict]:
    """
    Securely read a file from Cloud Storage.
    Returns file content and metadata.
    """
    client = _get_storage_client()
    bucket = client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    # Verify the blob exists
    if not blob.exists():
        raise InputValidationError("File does not exist in the specified bucket")

    # Validate file size before downloading
    _validate_file_size(blob)

    # Download content
    content = blob.download_as_bytes()

    # Compute integrity hash
    content_hash = _compute_file_hash(content)

    metadata = {
        "bucket": bucket_name,
        "file_name": file_name,
        "size_bytes": blob.size,
        "content_type": blob.content_type or "application/octet-stream",
        "created": blob.time_created.isoformat() if blob.time_created else None,
        "updated": blob.updated.isoformat() if blob.updated else None,
        "md5_hash": blob.md5_hash,
        "sha256_hash": content_hash,
        "etag": blob.etag,
    }

    return content, metadata


def _parse_file_content(content: bytes, content_type: str, file_name: str) -> dict:
    """
    Parse file content based on type. Validates structure.
    """
    result = {
        "record_count": 0,
        "parse_status": "unknown",
        "summary": {},
    }

    file_lower = file_name.lower()

    try:
        if file_lower.endswith(".json"):
            # Parse JSON with size limit already enforced
            text = content.decode("utf-8")
            data = json.loads(text)

            if isinstance(data, list):
                result["record_count"] = len(data)
                result["parse_status"] = "success"
                result["summary"] = {"type": "json_array", "items": len(data)}
            elif isinstance(data, dict):
                result["record_count"] = 1
                result["parse_status"] = "success"
                # Don't store actual keys/values - could contain sensitive data
                result["summary"] = {"type": "json_object", "top_level_keys": len(data)}
            else:
                result["parse_status"] = "success"
                result["summary"] = {"type": "json_primitive"}

        elif file_lower.endswith(".csv"):
            text = content.decode("utf-8")
            lines = text.strip().split("\n")
            # Count lines (excluding header)
            result["record_count"] = max(0, len(lines) - 1)
            result["parse_status"] = "success"
            result["summary"] = {
                "type": "csv",
                "total_lines": len(lines),
                "has_header": len(lines) > 0,
            }

        elif file_lower.endswith(".txt"):
            text = content.decode("utf-8")
            lines = text.strip().split("\n")
            result["record_count"] = len(lines)
            result["parse_status"] = "success"
            result["summary"] = {"type": "text", "line_count": len(lines)}

        else:
            result["parse_status"] = "unsupported_format"

    except (UnicodeDecodeError, json.JSONDecodeError) as e:
        result["parse_status"] = "parse_error"
        # Log error type but not content (could contain sensitive data)
        logger.warning("File parse error: %s", type(e).__name__)

    return result


def _write_to_firestore(document_id: str, data: dict) -> str:
    """
    Write processing results to Firestore.
    Uses a deterministic document ID to enable idempotency.
    """
    client = _get_firestore_client()

    # Sanitize document ID
    safe_doc_id = re.sub(r"[^a-zA-Z0-9_\-]", "_", document_id)[:500]

    doc_ref = client.collection(FIRESTORE_COLLECTION).document(safe_doc_id)

    # Add processing metadata
    data["processed_at"] = datetime.now(timezone.utc).isoformat()
    data["function_version"] = os.environ.get("K_REVISION", "unknown")

    # Use set with merge to be idempotent on retries
    doc_ref.set(data, merge=True)

    logger.info(
        "Written to Firestore: collection=%s, document=%s",
        FIRESTORE_COLLECTION,
        _sanitize_for_logging(safe_doc_id),
    )

    return safe_doc_id


def _publish_to_pubsub(message_data: dict) -> str:
    """
    Publish a notification message to Pub/Sub.
    Returns the published message ID.
    """
    if not PUBSUB_TOPIC:
        raise SecurityViolationError("PUBSUB_TOPIC environment variable not configured")

    # Validate topic format
    if not re.match(r"^projects/[a-z][a-z0-9\-]*[a-z0-9]/topics/[a-zA-Z][a-zA-Z0-9\-_.~+%]{0,254}$", PUBSUB_TOPIC):
        raise SecurityViolationError("Invalid Pub/Sub topic format")

    publisher = _get_pubsub_publisher()

    # Build message - exclude raw file content, only metadata
    safe_message = {
        "event_type": "file_processed",
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "file_name": message_data.get("file_name", ""),
        "bucket": message_data.get("bucket", ""),
        "status": message_data.get("status", "unknown"),
        "record_count": message_data.get("record_count", 0),
        "sha256_hash": message_data.get("sha256_hash", ""),
        "document_id": message_data.get("document_id", ""),
    }

    message_bytes = json.dumps(safe_message).encode("utf-8")

    # Publish with ordering key for consistency
    future = publisher.publish(
        PUBSUB_TOPIC,
        data=message_bytes,
        # Attributes for filtering
        event_type="file_processed",
        status=str(safe_message["status"]),
    )

    message_id = future.result(timeout=30)

    logger.info("Published to Pub/Sub: message_id=%s", message_id)

    return message_id


def process_file(event: dict, context: Any) -> None:
    """
    Cloud Function entry point triggered by Cloud Storage events.

    Args:
        event: The Cloud Storage event payload.
        context: The event context (metadata about the triggering event).
    """
    start_time = time.monotonic()
    file_name = None
    bucket_name = None

    try:
        # Extract and validate event data
        # These come from the GCS trigger - still validate as defense in depth
        bucket_name = event.get("bucket", "")
        file_name = event.get("name", "")
        event_type = getattr(context, "event_type", "unknown") if context else "unknown"

        logger.info(
            "Processing event: type=%s, bucket=%s, file=%s",
            _sanitize_for_logging(str(event_type)),
            _sanitize_for_logging(str(bucket_name)),
            _sanitize_for_logging(str(file_name)),
        )

        # Validate inputs even though they come from GCS trigger
        # (defense in depth against event injection)
        validated_bucket = _validate_bucket_name(bucket_name)
        validated_file = _validate_file_name(file_name)

        # Read file from Cloud Storage
        content, file_metadata = _read_file_from_storage(validated_bucket, validated_file)

        # Parse file content
        parse_result = _parse_file_content(
            content,
            file_metadata.get("content_type", ""),
            validated_file,
        )

        # Build Firestore document
        # Use content hash as part of document ID for idempotency
        content_hash = file_metadata["sha256_hash"]
        document_id = f"{validated_file}_{content_hash[:16]}"

        firestore_data = {
            "file_name": validated_file,
            "bucket": validated_bucket,
            "file_metadata": {
                "size_bytes": file_metadata["size_bytes"],
                "content_type": file_metadata["content_type"],
                "created": file_metadata["created"],
                "sha256_hash": content_hash,
            },
            "parse_result": parse_result,
            "status": "processed" if parse_result["parse_status"] == "success" else "error",
        }

        # Write to Firestore
        doc_id = _write_to_firestore(document_id, firestore_data)

        # Publish notification to Pub/Sub
        pubsub_message = {
            "file_name": validated_file,
            "bucket": validated_bucket,
            "status": firestore_data["status"],
            "record_count": parse_result["record_count"],
            "sha256_hash": content_hash,
            "document_id": doc_id,
        }

        message_id = _publish_to_pubsub(pubsub_message)

        elapsed = time.monotonic() - start_time
        logger.info(
            "Processing complete: file=%s, status=%s, records=%d, "
            "pubsub_msg=%s, duration=%.2fs",
            _sanitize_for_logging(validated_file),
            firestore_data["status"],
            parse_result["record_count"],
            message_id,
            elapsed,
        )

    except (InputValidationError, SecurityViolationError) as e:
        elapsed = time.monotonic() - start_time
        # Log the error type and message but not the input that caused it
        logger.error(
            "Validation/security error processing file: error_type=%s, duration=%.2fs",
            type(e).__name__,
            elapsed,
        )
        # For security violations, we may want to alert but not retry
        if isinstance(e, SecurityViolationError):
            logger.critical("Security violation detected - not retrying")
            # Don't re-raise to prevent retry of security violations
            return
        # Input validation errors also should not be retried
        return

    except gcp_exceptions.NotFound as e:
        logger.error("Resource not found: %s", type(e).__name__)
        # Don't retry - resource doesn't exist
        return

    except gcp_exceptions.PermissionDenied as e:
        logger.error("Permission denied - check service account IAM bindings")
        # Don't retry - permission issue needs manual fix
        return

    except (gcp_exceptions.ServiceUnavailable, gcp_exceptions.DeadlineExceeded) as e:
        elapsed = time.monotonic() - start_time
        logger.warning(
            "Transient error, will retry: error_type=%s, duration=%.2fs",
            type(e).__name__,
            elapsed,
        )
        # Re-raise to trigger Cloud Functions retry
        raise

    except Exception as e:
        elapsed = time.monotonic() - start_time
        logger.exception(
            "Unexpected error processing file: error_type=%s, duration=%.2fs",
            type(e).__name__,
            elapsed,
        )
        # Re-raise for retry on unexpected errors
        raise